<template>
    <div>
        <div class="modal fade " tabindex="-1" role="dialog" ref="modal">
            <div class="modal-dialog" role="document">
                <div class="modal-content">
                    <button type="button" class="close" data-dismiss="modal" aria-label="Close">
                        <i class="fal fa-times"></i>
                    </button>
                    <div class="modal-body">
                        <div class="quick-view">
                            <transition name="fade" mode="out-in">
                                <div class="quick-view-loading" v-if="isLoading" key="quick-view-loading">
                                    <span class="icon-loading"></span>
                                </div>
                                <div class="quick-view-content" v-else key="quick-view-ready">
                                    <div class="quick-view-content-row row ">
                                        <div class="quick-view-content-col col col-6">
                                            <div class="product-image">
                                                <div class="product-image-box">
                                                    <image-zoomer :src="activeImage"></image-zoomer>
                                                </div>
                                                <div class="product-image-carousel">
                                                    <carousel v-bind="carousel">
                                                        <slide v-for="(item , index) in data.images"
                                                               :key="`slide_${index}`" :data-index="index"
                                                               @slideclick="onClickSlide">
                                                            <div class="item-slide"
                                                                 :class="{ 'is-active' : activeSlide == index}">
                                                                <img :src="item.src" alt="">
                                                            </div>
                                                        </slide>
                                                    </carousel>
                                                </div>
                                            </div>
                                        </div>
                                        <div class="quick-view-content-col col col-6">
                                            <div class="product-title">
                                                <h1>{{data.title}}</h1>
                                            </div>
                                            <div class="product-supplier">
                                                <span>By</span>
                                                <strong>{{data.supplier.shop_name}}</strong>
                                            </div>
                                            <div class="product-short-description">
                                                <p>
                                                    {{ data.short_description}}
                                                </p>
                                            </div>
                                            <div class="product-properties">
                                                <div class="item-property"
                                                     v-for="(property , index ) in form.properties"
                                                     :key="`property_${index}`">
                                                    <div class="item-property-title">{{ property.name }}</div>
                                                    <div class="item-property-value">
                                                        <div class="item-value" v-for="(item, i) in property.data"
                                                             :key="`value_index${i}`"
                                                             :class="{ 'is-active' : activeOption({option : property.id , value : item.id }) }">
                                                            <template v-if="item.image && item.image.src">
                                                                <button @click.stop.prevent="selectOption(property.id , item.id , item.image )"
                                                                        type="button"
                                                                        class="btn btn-sm item-value-image"
                                                                        :title="item.name">
                                                                    <img :src="item.image.src" alt="">
                                                                </button>
                                                            </template>
                                                            <template v-else>
                                                                <button @click.stop.prevent="selectOption(property.id , item.id)"
                                                                        type="button"
                                                                        class="btn btn-sm item-value-text">
                                                                    {{item.name}}
                                                                </button>
                                                            </template>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="product-price">
                                                <div class="item-price-title">Price</div>
                                                <transition name="fade-transform" mode="out-in">
                                                    <div class="item-price-value" v-if="selectedProduct.is_selected"
                                                         key="price_1">
                                                        {{selectedProduct.price }}
                                                    </div>
                                                    <div class="item-price-value" v-else key="price_2">
                                                        {{selectedProduct.price }}
                                                    </div>
                                                </transition>
                                            </div>
                                            <div class="product-inventory">
                                                <transition name="fade-transform" mode="out-in">
                                                    <div v-if="selectedProduct.is_selected" key="inventory_1">
                                                        <span>Availability :</span> <strong>{{selectedProduct.inventory
                                                        | number_format }} in stock</strong>
                                                    </div>
                                                    <div v-else key="inventory_2">
                                                        <span>Availability :</span> <strong>{{data.inventory |
                                                        number_format }} for {{data.variants.length}} variants in
                                                        stock</strong>
                                                    </div>
                                                </transition>
                                            </div>
                                            <div class="product-actions">
                                                <button v-if="!data.isImported"
                                                        @click.stop.prevent="importProduct(data, $event)"
                                                        :class="{'btn-importing': isImportLoading}"
                                                        class="btn btn-warning btn-import-list">
                                                    <i class="icon-load fas fa-shopping-bag"></i>
                                                    <div class="circle-loader">
                                                        <div class="checkmark draw"></div>
                                                    </div>
                                                    Add to Import List
                                                </button>
                                                <button v-if="data.isImported"
                                                        @click.stop.prevent="removeImported(data, $event)"
                                                        :class="{'btn-importing': isImportLoading}"
                                                        class="btn black-button-style">
                                                    <i class="icon-load fas fa-trash"></i>
                                                    <div class="circle-loader">
                                                        <div class="checkmark draw"></div>
                                                    </div>
                                                    Remove imported list
                                                </button>
                                                <button @click.stop.prevent="handleViewDetail()" type="button"
                                                        class="btn btn-light btn-view-detail">View detail
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </transition>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
    import ImageZoomer from '@/modules/home/_components/partials/vue-pic-zoom'
    import {Carousel, Slide} from '@/components/v-carousel'
    import helper from '@/plugins/helper'
    import mixin from '@/modules/home/_mixins/product-detail'
    import {mapActions, mapGetters} from 'vuex'

    export default {
        name: 'QuickView',
        mixins: [mixin],
        components: {
            ImageZoomer, Carousel, Slide
        },
        data() {
            return {
                data: null,
                error: null,
                isLoading: true,
                isImportLoading: false
            }
        },
        methods: {
            ...mapActions({
                callImportProduct: "$_Home/IMPORT_PRODUCT"
            }),
            ...mapGetters({
                seller: '$_Seller/getSeller',
            }),
            importProduct(product, event) {
                if (this.seller()) {
                    let id = product.id
                    let target = $(event.target)
                    this.isImportLoading = true
                    let defaultShop = this.seller().shops.filter(function (el, idx) {
                        return el.shop_default == 1
                    });
                    let temp = {
                        "product_id": id,
                        "shop_id": defaultShop[0].id
                    }
                    this.callImportProduct(temp).then(res => {
                        if (res.data.status) {
                            this.data.isImported = true
                        } else {
                            $notify({
                                content: 'import product fail',
                                type: 'danger'
                            })
                        }
                        this.isImportLoading = false
                    })
                } else {
                    $(this.$refs.modal).modal('hide')
                    this.$router.push({
                        name: "Login"
                    })
                }
            },
            removeImported(product) {
                let id = product.id
                let target = $(event.target)
                this.isLoading = true
                let defaultShop = this.seller().shops.filter(function (el, idx) {
                    return el.shop_default == 1
                });
                let temp = {
                    "product_id": id,
                    "shop_id": defaultShop[0].id
                }
                this.removeImportedProduct(temp).then(res => {
                    if (res.data.status) {
                        this.ProductInfo.isImported = false
                    } else {
                        $notify({
                            content: 'Remove Imported Product fail',
                            type: 'danger'
                        })
                    }
                    this.isLoading = false
                })
            },
            handleViewDetail() {
                var slug = `${this.data.handle}-${this.data.id}`
                $(this.$refs.modal).modal('hide')
                setTimeout(() => {
                    this.$router.push({
                        name: 'ProductDetail',
                        params: {
                            id: slug
                        }
                    })
                }, 500);
            }
        },
        mounted() {
            if (EventBus) {
                EventBus.$on('show-quick-view', ({id}) => {
                    $(this.$refs.modal).modal('show')
                    this.isLoading = true
                    this.$store.dispatch('$_Home/GET_PRODUCT_DETAIL', {id: id}).then(res => {
                        let {status, data} = res

                        if (status) {
                            this.data = data
                        } else {
                            this.error = 'error'
                        }
                        setTimeout(() => {
                            this.isLoading = false;
                        }, 500);
                    })
                    this.$nextTick(() => {
                        $(this.$refs.modal).on('hidden.bs.modal', () => {
                            this.product = null
                            this.error = null
                            this.isLoading = true
                            this.activeSlide = 0
                        })
                    })

                })
            }
        }
    }
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';

    $border-color: #eee;
    .modal {
        &-dialog {
            max-width: 1100px;
            .close {
                position: absolute;
                right: 10px;
                top: 10px;
                font-size: 20px;
                z-index: 10;
                width: 28px;
                height: 28px;
                border-radius: 50%;
                overflow: hidden;
                display: inline-flex;
                justify-content: center;
                align-items: center;
                &:hover {
                    background: rgba(0, 0, 0, 0.15)
                }
            }
            .modal-body {
                padding: 30px 50px;
            }
        }
    }

    .quick-view {
        &-loading {
            width: 100%;
            height: 400px;
            display: flex;
            justify-content: center;
            align-items: center;
            .icon-loading {
                height: 100px;
                width: 100px;
                background: $yellow;
            }
        }
        &-content {
            min-height: 400px;
            &-row {
                margin-left: -25px;
                margin-right: -25px;
            }
            &-col {
                padding-left: 25px;
                padding-right: 25px;
            }
        }

    }

    .product {
        &-image {
            position: relative;
            &-box {
                border: 1px solid $border-color;
                display: flex;
                justify-content: center;
            }
            &-carousel {
                width: 100%;
                height: 100px;
                overflow: hidden;
                padding: 15px 0px;

                .item-slide {
                    width: 70px;
                    height: 70px;
                    border: 2px solid $border-color;
                    display: flex;
                    justify-content: center;
                    align-items: center;
                    transition: all 0.3s ease;
                    img {
                        max-width: 100%;
                        max-height: 100%;
                    }
                    &.is-active {
                        border-color: $yellow;
                    }
                }
            }
        }
        &-title {
            margin-bottom: 5px;
            h1 {
                font-size: 20px;
                font-weight: 500;
                margin: 0;
            }
        }
        &-supplier {
            span, strong {
                display: inline-block;
            }
            strong {
                color: $yellow;
                margin-left: 5px;
            }
        }
        &-properties {
            .item-property {
                margin-bottom: 20px;
                &-title {
                    font-size: 16px;
                    font-weight: 500;
                    margin-bottom: 5px;
                    line-height: 16px;
                    text-transform: uppercase;
                }
                &-value {
                    display: flex;
                    flex-direction: row;
                    flex-wrap: wrap;
                    margin: 0 -7px;
                    .item-value {
                        padding: 0 5px;
                        margin: 0 0 10px;
                        .btn {
                            &:focus {
                                outline: none;
                                box-shadow: none;
                            }
                        }
                        &.is-active {
                            .item-value {
                                &-image {
                                    border-color: $yellow;
                                }
                                &-text {
                                    border-color: $yellow;
                                }
                            }
                        }
                        &:first-child {
                            margin-left: 0;
                        }
                        &-image {
                            padding: 0;
                            height: 40px;
                            width: 40px;
                            min-width: 40px;
                            border-radius: 8px;
                            border: 2px solid #ddd;
                            overflow: hidden;
                            img {
                                max-width: 100%;
                                max-height: 100%;
                            }
                        }
                        &-text {
                            min-height: 28px;
                            padding: 0 7px;
                            min-width: 60px;
                            overflow: hidden;
                            border: 1px solid #ddd;
                            border-radius: 19px;
                        }
                    }
                }
            }
        }
        &-price {
            .item-price {
                &-title {
                    font-size: 16px;
                    font-weight: bold;
                    margin-bottom: 5px;
                    line-height: 16px;
                    text-transform: uppercase;
                }
                &-value {
                    font-size: 35px;
                    font-weight: 500;
                    margin-bottom: 5px;
                    line-height: 35px;
                }
            }
        }
        &-actions {
            margin-top: 30px;
            display: flex;
            flex-wrap: nowrap;
            flex-direction: row;
            .btn {
                padding: 0 15px;
                border-radius: 21px;
                height: 42px;
                line-height: 42px;
                align-items: center;
                justify-content: center;
                display: inline-flex;
                flex: 1 1;
                margin: 0 5px 5px 5px;
                font-size: 14px;
                font-weight: 500;
                &-import-list {
                    color: #fff;
                    background: $yellow;
                }
                &.btn-importing {
                    .icon-load {
                        display: none;
                    }
                    .circle-loader {
                        display: inline-block;
                    }
                }
                &-view-detail {
                    border: 1px solid #ccc;
                }
            }
        }
        &-return-policy {
            display: flex;
            flex-wrap: nowrap;
            flex-direction: row;
            .return-policy {
                &-title {
                    font-size: 14px;
                    text-transform: uppercase;
                    white-space: nowrap;
                    font-weight: 500;
                }
                &-value {
                    padding-left: 15px;
                    strong {
                        font-size: 14px;
                        font-weight: 500;
                    }
                    p {
                        font-size: 12px;
                    }
                }
            }
        }
    }
</style>


